import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { useIsAuthenticated, useMsal } from '@azure/msal-react';
import { loginRequest, isDevelopmentMode } from './config/authConfig';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Profile from './pages/Profile';
import Family from './pages/Family';
import ConsentAudit from './pages/ConsentAudit';
import Documents from './pages/Documents';
import Transfers from './pages/Transfers';
import Login from './pages/Login';

function App() {
  const isAuthenticated = useIsAuthenticated();
  const { instance } = useMsal();

  const handleLogin = () => {
    instance.loginRedirect(loginRequest);
  };

  // In development mode without Azure AD, allow access
  const canAccess = isAuthenticated || isDevelopmentMode;

  if (!canAccess) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Layout />}>
          <Route index element={<Navigate to="/dashboard" replace />} />
          <Route path="dashboard" element={<Dashboard />} />
          <Route path="profile" element={<Profile />} />
          <Route path="family" element={<Family />} />
          <Route path="consent" element={<ConsentAudit />} />
          <Route path="documents" element={<Documents />} />
          <Route path="transfers" element={<Transfers />} />
          <Route path="*" element={<Navigate to="/dashboard" replace />} />
        </Route>
      </Routes>
    </BrowserRouter>
  );
}

export default App;

