import { useState, useEffect, useCallback, useMemo } from 'react';
import axios from 'axios';
import { API_BASE_URL } from '../config/apiConfig';
import { MOCK_PATIENT_ID } from '../config/mockUser';

interface MedicalProfile {
  // Personal Information
  firstName: string;
  lastName: string;
  dateOfBirth: string;
  gender: string;
  phone: string;
  email: string;
  address: string;
  maritalStatus: string;
  occupation: string;
  
  // Emergency Contact
  emergencyContact: {
    name: string;
    relationship: string;
    phone: string;
    email: string;
  };
  
  // Medical Information
  bloodType: string;
  height: string;
  weight: string;
  allergies: string[];
  currentMedications: string[];
  pastDiagnoses: string[];
  familyHistory: string[];
  surgicalHistory: string[];
  
  // Insurance Information
  primaryInsurance: {
    provider: string;
    policyNumber: string;
    groupNumber: string;
  };
  
  // Additional Information
  preferredLanguage: string;
  religion: string;
  organDonor: boolean;
  advanceDirective: boolean;
}

export default function Profile() {
  const [isEditing, setIsEditing] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [activeSection, setActiveSection] = useState('personal');
  
  const [profile, setProfile] = useState<MedicalProfile>({
    firstName: 'Ashok',
    lastName: 'Thotakura',
    dateOfBirth: '1985-06-15',
    gender: 'Male',
    phone: '+1 (555) 123-4567',
    email: 'athotakura@err.com',
    address: '123 Main Street, Anytown, ST 12345',
    maritalStatus: 'Married',
    occupation: 'Software Engineer',
    emergencyContact: {
      name: 'Jane Doe',
      relationship: 'Spouse',
      phone: '+1 (555) 987-6543',
      email: 'jane.doe@email.com',
    },
    bloodType: 'O+',
    height: '5\'10"',
    weight: '175 lbs',
    allergies: ['Penicillin', 'Shellfish'],
    currentMedications: ['Lisinopril 10mg', 'Metformin 500mg'],
    pastDiagnoses: ['Hypertension', 'Type 2 Diabetes'],
    familyHistory: ['Heart Disease (Father)', 'Diabetes (Mother)'],
    surgicalHistory: ['Appendectomy (2010)'],
    primaryInsurance: {
      provider: 'Blue Cross Blue Shield',
      policyNumber: 'BC123456789',
      groupNumber: 'GRP001',
    },
    preferredLanguage: 'English',
    religion: 'None',
    organDonor: true,
    advanceDirective: false,
  });

  const [newAllergy, setNewAllergy] = useState('');
  const [newMedication, setNewMedication] = useState('');
  const [newDiagnosis, setNewDiagnosis] = useState('');
  const [newFamilyHistory, setNewFamilyHistory] = useState('');
  const [newSurgery, setNewSurgery] = useState('');

  const loadProfile = useCallback(async () => {
    setIsLoading(true);
    try {
      // Load patient basic information
      const patientResponse = await axios.get(`${API_BASE_URL}/patients/${MOCK_PATIENT_ID}`);
      const patientData = patientResponse.data;

      // Load allergies
      const allergiesResponse = await axios.get(`${API_BASE_URL}/allergies/patient/${MOCK_PATIENT_ID}`);
      const allergies = allergiesResponse.data.map((allergy: any) => allergy.allergenName);

      // Load insurance information
      const insuranceResponse = await axios.get(`${API_BASE_URL}/insurance/patient/${MOCK_PATIENT_ID}`);
      const primaryInsurance = insuranceResponse.data.length > 0 ? insuranceResponse.data[0] : null;

      // Update profile with real data
      setProfile(prev => ({
        ...prev,
        firstName: patientData.firstName || prev.firstName,
        lastName: patientData.lastName || prev.lastName,
        dateOfBirth: patientData.dateOfBirth ? new Date(patientData.dateOfBirth).toISOString().split('T')[0] : prev.dateOfBirth,
        gender: patientData.gender || prev.gender,
        phone: patientData.phoneNumber || prev.phone,
        email: patientData.email || prev.email,
        address: `${patientData.addressLine1 || ''} ${patientData.addressLine2 || ''} ${patientData.city || ''} ${patientData.state || ''} ${patientData.zipCode || ''}`.trim() || prev.address,
        maritalStatus: patientData.maritalStatus || prev.maritalStatus,
        occupation: prev.occupation, // Not in API yet
        emergencyContact: {
          name: patientData.emergencyContactName || prev.emergencyContact.name,
          relationship: patientData.emergencyContactRelationship || prev.emergencyContact.relationship,
          phone: patientData.emergencyContactPhone || prev.emergencyContact.phone,
          email: prev.emergencyContact.email, // Not in API yet
        },
        allergies: allergies.length > 0 ? allergies : prev.allergies,
        primaryInsurance: primaryInsurance ? {
          provider: primaryInsurance.payerName || prev.primaryInsurance.provider,
          policyNumber: primaryInsurance.memberId || prev.primaryInsurance.policyNumber,
          groupNumber: primaryInsurance.groupNumber || prev.primaryInsurance.groupNumber,
        } : prev.primaryInsurance,
        preferredLanguage: patientData.preferredLanguage || prev.preferredLanguage,
        religion: prev.religion, // Not in API yet
        organDonor: prev.organDonor, // Not in API yet
        advanceDirective: prev.advanceDirective, // Not in API yet
      }));

      console.log('Profile loaded successfully from database');
    } catch (error) {
      console.error('Error loading profile:', error);
      // Keep existing data if API fails
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Load profile data from API
  useEffect(() => {
    loadProfile();
  }, [loadProfile]);

  const saveProfile = async () => {
    setIsSaving(true);
    try {
      // Update patient basic information
      const patientUpdateData = {
        firstName: profile.firstName,
        lastName: profile.lastName,
        email: profile.email,
        phoneNumber: profile.phone,
        addressLine1: profile.address.split(',')[0] || profile.address,
        addressLine2: '',
        city: profile.address.split(',')[1]?.trim() || '',
        state: profile.address.split(',')[2]?.trim() || '',
        zipCode: profile.address.split(',')[3]?.trim() || '',
        maritalStatus: profile.maritalStatus,
        preferredLanguage: profile.preferredLanguage,
        emergencyContactName: profile.emergencyContact.name,
        emergencyContactPhone: profile.emergencyContact.phone,
        emergencyContactRelationship: profile.emergencyContact.relationship,
      };

      await axios.put(`${API_BASE_URL}/patients/${MOCK_PATIENT_ID}`, patientUpdateData);

      // Update allergies (add new ones)
      for (const allergy of profile.allergies) {
        try {
          await axios.post(`${API_BASE_URL}/allergies`, {
            patientId: MOCK_PATIENT_ID,
            allergenName: allergy,
            allergenType: 'Medication',
            severity: 'Moderate',
            clinicalStatus: 'Active',
            reaction: 'Allergic reaction',
            onsetDate: new Date().toISOString(),
            verificationStatus: 'Confirmed'
          });
        } catch (error) {
          // Allergy might already exist, continue
          console.log('Allergy might already exist:', allergy);
        }
      }

      // Update insurance information
      if (profile.primaryInsurance.provider) {
        try {
          await axios.post(`${API_BASE_URL}/insurance`, {
            patientId: MOCK_PATIENT_ID,
            payerName: profile.primaryInsurance.provider,
            planName: 'Primary Plan',
            planType: 'Primary',
            memberId: profile.primaryInsurance.policyNumber,
            groupNumber: profile.primaryInsurance.groupNumber,
            groupName: 'Primary Group',
            effectiveDate: new Date().toISOString(),
            expirationDate: new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(), // 1 year from now
            priority: 1,
            isActive: true
          });
        } catch (error) {
          // Insurance might already exist, continue
          console.log('Insurance might already exist');
        }
      }
      
      setIsEditing(false);
      alert('Profile saved successfully to database!');
      console.log('Profile saved successfully to database');
    } catch (error) {
      console.error('Error saving profile:', error);
      alert('Error saving profile. Please try again.');
    } finally {
      setIsSaving(false);
    }
  };

  const handleInputChange = (field: string, value: string | boolean) => {
    setProfile(prev => ({
      ...prev,
      [field]: value,
    }));
  };

  const handleEmergencyContactChange = (field: string, value: string) => {
    setProfile(prev => ({
      ...prev,
      emergencyContact: {
        ...prev.emergencyContact,
        [field]: value,
      },
    }));
  };

  const handleInsuranceChange = (field: string, value: string) => {
    setProfile(prev => ({
      ...prev,
      primaryInsurance: {
        ...prev.primaryInsurance,
        [field]: value,
      },
    }));
  };

  const addToList = (listName: keyof MedicalProfile, value: string, setter: (value: string) => void) => {
    if (value.trim()) {
      setProfile(prev => ({
        ...prev,
        [listName]: [...(prev[listName] as string[]), value.trim()],
      }));
      setter('');
    }
  };

  const removeFromList = (listName: keyof MedicalProfile, index: number) => {
    setProfile(prev => ({
      ...prev,
      [listName]: (prev[listName] as string[]).filter((_, i) => i !== index),
    }));
  };

  const sections = useMemo(() => [
    { id: 'personal', label: 'Personal Info', icon: '👤' },
    { id: 'medical', label: 'Medical Info', icon: '🏥' },
    { id: 'emergency', label: 'Emergency Contact', icon: '🚨' },
    { id: 'insurance', label: 'Insurance', icon: '💳' },
    { id: 'additional', label: 'Additional', icon: '📋' },
  ], []);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-500 mx-auto mb-4"></div>
          <p className="text-neutral-600">Loading profile...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div style={{width: '40px', height: '40px', background: 'linear-gradient(135deg, #0A4FD5 0%, #0891B2 100%)', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
              <svg style={{width: '20px', height: '20px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold text-neutral-900">Medical Profile</h1>
              <p className="text-neutral-600 text-sm">Complete medical information for healthcare providers</p>
            </div>
          </div>
          <div className="flex gap-2">
            {isEditing && (
              <button
                onClick={() => setIsEditing(false)}
                className="px-4 py-2 border-2 border-neutral-300 rounded-lg hover:bg-neutral-50 font-semibold text-neutral-700 transition-all"
              >
                Cancel
              </button>
            )}
            <button
              onClick={isEditing ? saveProfile : () => setIsEditing(true)}
              disabled={isSaving}
              className="bg-primary-500 text-white px-4 py-2 rounded-lg font-semibold hover:bg-primary-600 transition-all flex items-center gap-2 disabled:opacity-50"
            >
              {isSaving ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
                  Saving...
                </>
              ) : isEditing ? (
                <>
                  <svg style={{width: '16px', height: '16px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  Save Changes
                </>
              ) : (
                <>
                  <svg style={{width: '16px', height: '16px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                  </svg>
                  Edit Profile
                </>
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-2">
        <div className="flex space-x-1 overflow-x-auto">
          {sections.map((section) => (
          <button
              key={section.id}
              onClick={() => setActiveSection(section.id)}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold whitespace-nowrap transition-all ${
                activeSection === section.id
                  ? 'bg-primary-100 text-primary-700 border border-primary-200'
                  : 'text-neutral-600 hover:text-primary-600 hover:bg-neutral-50'
              }`}
            >
              <span>{section.icon}</span>
              {section.label}
          </button>
          ))}
        </div>
        </div>

      {/* Personal Information Section */}
      {activeSection === 'personal' && (
        <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
          <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
            <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #0A4FD5 0%, #0891B2 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
              <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
              </svg>
            </div>
            Personal Information
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">First Name</label>
              {isEditing ? (
            <input
              type="text"
                  value={profile.firstName}
                  onChange={(e) => handleInputChange('firstName', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.firstName}</p>
              )}
          </div>
          <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Last Name</label>
              {isEditing ? (
            <input
              type="text"
                  value={profile.lastName}
                  onChange={(e) => handleInputChange('lastName', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.lastName}</p>
              )}
          </div>
          <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Date of Birth</label>
              {isEditing ? (
            <input
              type="date"
                  value={profile.dateOfBirth}
                  onChange={(e) => handleInputChange('dateOfBirth', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{new Date(profile.dateOfBirth).toLocaleDateString()}</p>
              )}
          </div>
          <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Gender</label>
              {isEditing ? (
            <select
                  value={profile.gender}
                  onChange={(e) => handleInputChange('gender', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                  <option value="Other">Other</option>
            </select>
              ) : (
                <p className="text-neutral-900 font-medium">{profile.gender}</p>
              )}
            </div>
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Phone Number</label>
              {isEditing ? (
                <input
                  type="tel"
                  value={profile.phone}
                  onChange={(e) => handleInputChange('phone', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.phone}</p>
              )}
          </div>
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Email Address</label>
              {isEditing ? (
            <input
              type="email"
                  value={profile.email}
                  onChange={(e) => handleInputChange('email', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.email}</p>
              )}
            </div>
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Marital Status</label>
              {isEditing ? (
                <select
                  value={profile.maritalStatus}
                  onChange={(e) => handleInputChange('maritalStatus', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="Single">Single</option>
                  <option value="Married">Married</option>
                  <option value="Divorced">Divorced</option>
                  <option value="Widowed">Widowed</option>
                </select>
              ) : (
                <p className="text-neutral-900 font-medium">{profile.maritalStatus}</p>
              )}
          </div>
          <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Occupation</label>
              {isEditing ? (
            <input
                  type="text"
                  value={profile.occupation}
                  onChange={(e) => handleInputChange('occupation', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.occupation}</p>
              )}
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Address</label>
              {isEditing ? (
                <textarea
                  value={profile.address}
                  onChange={(e) => handleInputChange('address', e.target.value)}
                  rows={3}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.address}</p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Medical Information Section */}
      {activeSection === 'medical' && (
        <div className="space-y-6">
          {/* Basic Medical Info */}
          <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
            <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
              <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #059669 0%, #10B981 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
                <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                </svg>
              </div>
              Basic Medical Information
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div>
                <label className="block text-sm font-semibold text-neutral-700 mb-1">Blood Type</label>
                {isEditing ? (
            <select
                    value={profile.bloodType}
                    onChange={(e) => handleInputChange('bloodType', e.target.value)}
                    className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  >
                    <option value="A+">A+</option>
                    <option value="A-">A-</option>
                    <option value="B+">B+</option>
                    <option value="B-">B-</option>
                    <option value="AB+">AB+</option>
                    <option value="AB-">AB-</option>
                    <option value="O+">O+</option>
                    <option value="O-">O-</option>
            </select>
                ) : (
                  <p className="text-neutral-900 font-medium">{profile.bloodType}</p>
                )}
              </div>
              <div>
                <label className="block text-sm font-semibold text-neutral-700 mb-1">Height</label>
                {isEditing ? (
                  <input
                    type="text"
                    value={profile.height}
                    onChange={(e) => handleInputChange('height', e.target.value)}
                    placeholder="e.g., 5'10&quot;"
                    className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  />
                ) : (
                  <p className="text-neutral-900 font-medium">{profile.height}</p>
                )}
              </div>
              <div>
                <label className="block text-sm font-semibold text-neutral-700 mb-1">Weight</label>
                {isEditing ? (
                  <input
                    type="text"
                    value={profile.weight}
                    onChange={(e) => handleInputChange('weight', e.target.value)}
                    placeholder="e.g., 175 lbs"
                    className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  />
                ) : (
                  <p className="text-neutral-900 font-medium">{profile.weight}</p>
                )}
              </div>
            </div>
          </div>

          {/* Allergies */}
          <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
            <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
              <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #DC2626 0%, #EF4444 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
                <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              Allergies
            </h2>
            <div className="space-y-3">
              {profile.allergies.map((allergy, index) => (
                <div key={index} className="flex items-center justify-between bg-red-50 border border-red-200 rounded-lg p-3">
                  <span className="text-red-800 font-medium">{allergy}</span>
                  {isEditing && (
                    <button
                      onClick={() => removeFromList('allergies', index)}
                      className="text-red-600 hover:text-red-800"
                    >
                      <svg style={{width: '16px', height: '16px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    </button>
                  )}
                </div>
              ))}
              {isEditing && (
                <div className="flex gap-2">
            <input
              type="text"
                    value={newAllergy}
                    onChange={(e) => setNewAllergy(e.target.value)}
                    placeholder="Add new allergy"
                    className="flex-1 px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  />
                  <button
                    onClick={() => addToList('allergies', newAllergy, setNewAllergy)}
                    className="bg-red-500 text-white px-4 py-2 rounded-lg hover:bg-red-600 transition-all"
                  >
                    Add
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Current Medications */}
          <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
            <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
              <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #0891B2 0%, #06B6D4 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
                <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
                </svg>
              </div>
              Current Medications
            </h2>
            <div className="space-y-3">
              {profile.currentMedications.map((medication, index) => (
                <div key={index} className="flex items-center justify-between bg-blue-50 border border-blue-200 rounded-lg p-3">
                  <span className="text-blue-800 font-medium">{medication}</span>
                  {isEditing && (
                    <button
                      onClick={() => removeFromList('currentMedications', index)}
                      className="text-blue-600 hover:text-blue-800"
                    >
                      <svg style={{width: '16px', height: '16px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    </button>
                  )}
                </div>
              ))}
              {isEditing && (
                <div className="flex gap-2">
              <input
                type="text"
                    value={newMedication}
                    onChange={(e) => setNewMedication(e.target.value)}
                    placeholder="Add new medication"
                    className="flex-1 px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  />
                  <button
                    onClick={() => addToList('currentMedications', newMedication, setNewMedication)}
                    className="bg-blue-500 text-white px-4 py-2 rounded-lg hover:bg-blue-600 transition-all"
                  >
                    Add
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Past Diagnoses */}
          <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
            <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
              <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #7C3AED 0%, #8B5CF6 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
                <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              Past Diagnoses
            </h2>
            <div className="space-y-3">
              {profile.pastDiagnoses.map((diagnosis, index) => (
                <div key={index} className="flex items-center justify-between bg-purple-50 border border-purple-200 rounded-lg p-3">
                  <span className="text-purple-800 font-medium">{diagnosis}</span>
                  {isEditing && (
                    <button
                      onClick={() => removeFromList('pastDiagnoses', index)}
                      className="text-purple-600 hover:text-purple-800"
                    >
                      <svg style={{width: '16px', height: '16px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    </button>
                  )}
                </div>
              ))}
              {isEditing && (
                <div className="flex gap-2">
              <input
                type="text"
                    value={newDiagnosis}
                    onChange={(e) => setNewDiagnosis(e.target.value)}
                    placeholder="Add new diagnosis"
                    className="flex-1 px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  />
                  <button
                    onClick={() => addToList('pastDiagnoses', newDiagnosis, setNewDiagnosis)}
                    className="bg-purple-500 text-white px-4 py-2 rounded-lg hover:bg-purple-600 transition-all"
                  >
                    Add
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Family History */}
          <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
            <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
              <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #059669 0%, #10B981 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
                <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
                </svg>
              </div>
              Family History
            </h2>
            <div className="space-y-3">
              {profile.familyHistory.map((history, index) => (
                <div key={index} className="flex items-center justify-between bg-green-50 border border-green-200 rounded-lg p-3">
                  <span className="text-green-800 font-medium">{history}</span>
                  {isEditing && (
                    <button
                      onClick={() => removeFromList('familyHistory', index)}
                      className="text-green-600 hover:text-green-800"
                    >
                      <svg style={{width: '16px', height: '16px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    </button>
                  )}
                </div>
              ))}
              {isEditing && (
                <div className="flex gap-2">
              <input
                type="text"
                    value={newFamilyHistory}
                    onChange={(e) => setNewFamilyHistory(e.target.value)}
                    placeholder="Add family history item"
                    className="flex-1 px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  />
                  <button
                    onClick={() => addToList('familyHistory', newFamilyHistory, setNewFamilyHistory)}
                    className="bg-green-500 text-white px-4 py-2 rounded-lg hover:bg-green-600 transition-all"
                  >
                    Add
                  </button>
            </div>
              )}
          </div>
        </div>

          {/* Surgical History */}
          <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
            <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
              <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #EA580C 0%, #F97316 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
                <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 100 4m0-4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 100 4m0-4v2m0-6V4" />
                </svg>
              </div>
              Surgical History
            </h2>
            <div className="space-y-3">
              {profile.surgicalHistory.map((surgery, index) => (
                <div key={index} className="flex items-center justify-between bg-orange-50 border border-orange-200 rounded-lg p-3">
                  <span className="text-orange-800 font-medium">{surgery}</span>
        {isEditing && (
            <button
                      onClick={() => removeFromList('surgicalHistory', index)}
                      className="text-orange-600 hover:text-orange-800"
            >
                      <svg style={{width: '16px', height: '16px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                      </svg>
            </button>
                  )}
                </div>
              ))}
              {isEditing && (
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={newSurgery}
                    onChange={(e) => setNewSurgery(e.target.value)}
                    placeholder="Add surgical procedure"
                    className="flex-1 px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  />
            <button
                    onClick={() => addToList('surgicalHistory', newSurgery, setNewSurgery)}
                    className="bg-orange-500 text-white px-4 py-2 rounded-lg hover:bg-orange-600 transition-all"
            >
                    Add
            </button>
          </div>
        )}
      </div>
          </div>
        </div>
      )}

      {/* Emergency Contact Section */}
      {activeSection === 'emergency' && (
        <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
          <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
            <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #DC2626 0%, #EF4444 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
              <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            Emergency Contact
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Name</label>
              {isEditing ? (
            <input
              type="text"
                  value={profile.emergencyContact.name}
                  onChange={(e) => handleEmergencyContactChange('name', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.emergencyContact.name}</p>
              )}
            </div>
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Relationship</label>
              {isEditing ? (
                <select
                  value={profile.emergencyContact.relationship}
                  onChange={(e) => handleEmergencyContactChange('relationship', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="Spouse">Spouse</option>
                  <option value="Parent">Parent</option>
                  <option value="Child">Child</option>
                  <option value="Sibling">Sibling</option>
                  <option value="Friend">Friend</option>
                  <option value="Other">Other</option>
                </select>
              ) : (
                <p className="text-neutral-900 font-medium">{profile.emergencyContact.relationship}</p>
              )}
          </div>
          <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Phone Number</label>
              {isEditing ? (
            <input
              type="tel"
                  value={profile.emergencyContact.phone}
                  onChange={(e) => handleEmergencyContactChange('phone', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.emergencyContact.phone}</p>
              )}
            </div>
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Email Address</label>
              {isEditing ? (
                <input
                  type="email"
                  value={profile.emergencyContact.email}
                  onChange={(e) => handleEmergencyContactChange('email', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.emergencyContact.email}</p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Insurance Section */}
      {activeSection === 'insurance' && (
        <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
          <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
            <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #0891B2 0%, #06B6D4 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
              <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z" />
              </svg>
            </div>
            Insurance Information
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Provider</label>
              {isEditing ? (
                <input
                  type="text"
                  value={profile.primaryInsurance.provider}
                  onChange={(e) => handleInsuranceChange('provider', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.primaryInsurance.provider}</p>
              )}
            </div>
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Policy Number</label>
              {isEditing ? (
                <input
                  type="text"
                  value={profile.primaryInsurance.policyNumber}
                  onChange={(e) => handleInsuranceChange('policyNumber', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.primaryInsurance.policyNumber}</p>
              )}
          </div>
          <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Group Number</label>
              {isEditing ? (
            <input
              type="text"
                  value={profile.primaryInsurance.groupNumber}
                  onChange={(e) => handleInsuranceChange('groupNumber', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                />
              ) : (
                <p className="text-neutral-900 font-medium">{profile.primaryInsurance.groupNumber}</p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Additional Information Section */}
      {activeSection === 'additional' && (
        <div className="bg-white rounded-lg shadow-sm border border-neutral-200 p-6">
          <h2 className="text-lg font-semibold text-neutral-900 mb-4 flex items-center gap-2">
            <div style={{width: '32px', height: '32px', background: 'linear-gradient(135deg, #7C3AED 0%, #8B5CF6 100%)', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
              <svg style={{width: '16px', height: '16px', color: 'white'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
            </div>
            Additional Information
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Preferred Language</label>
              {isEditing ? (
                <select
                  value={profile.preferredLanguage}
                  onChange={(e) => handleInputChange('preferredLanguage', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="English">English</option>
                  <option value="Spanish">Spanish</option>
                  <option value="French">French</option>
                  <option value="German">German</option>
                  <option value="Chinese">Chinese</option>
                  <option value="Other">Other</option>
                </select>
              ) : (
                <p className="text-neutral-900 font-medium">{profile.preferredLanguage}</p>
              )}
            </div>
            <div>
              <label className="block text-sm font-semibold text-neutral-700 mb-1">Religion</label>
              {isEditing ? (
                <select
                  value={profile.religion}
                  onChange={(e) => handleInputChange('religion', e.target.value)}
                  className="w-full px-3 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="None">None</option>
                  <option value="Christianity">Christianity</option>
                  <option value="Islam">Islam</option>
                  <option value="Judaism">Judaism</option>
                  <option value="Hinduism">Hinduism</option>
                  <option value="Buddhism">Buddhism</option>
                  <option value="Other">Other</option>
                </select>
              ) : (
                <p className="text-neutral-900 font-medium">{profile.religion}</p>
              )}
            </div>
            <div className="md:col-span-2">
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <label className="text-sm font-semibold text-neutral-700">Organ Donor</label>
                    <p className="text-xs text-neutral-500">Registered as an organ donor</p>
                  </div>
                  {isEditing ? (
                    <input
                      type="checkbox"
                      checked={profile.organDonor}
                      onChange={(e) => handleInputChange('organDonor', e.target.checked)}
                      className="w-4 h-4 text-primary-600 rounded focus:ring-primary-500"
                    />
                  ) : (
                    <span className={`px-2 py-1 rounded-full text-xs font-semibold ${
                      profile.organDonor ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800'
                    }`}>
                      {profile.organDonor ? 'Yes' : 'No'}
                    </span>
                  )}
                </div>
                <div className="flex items-center justify-between">
                  <div>
                    <label className="text-sm font-semibold text-neutral-700">Advance Directive</label>
                    <p className="text-xs text-neutral-500">Has advance directive on file</p>
                  </div>
                  {isEditing ? (
                    <input
                      type="checkbox"
                      checked={profile.advanceDirective}
                      onChange={(e) => handleInputChange('advanceDirective', e.target.checked)}
                      className="w-4 h-4 text-primary-600 rounded focus:ring-primary-500"
                    />
                  ) : (
                    <span className={`px-2 py-1 rounded-full text-xs font-semibold ${
                      profile.advanceDirective ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800'
                    }`}>
                      {profile.advanceDirective ? 'Yes' : 'No'}
                    </span>
                  )}
                </div>
              </div>
          </div>
        </div>
      </div>
      )}
    </div>
  );
}