export default function Documents() {
  const documents = [
    { id: '1', name: 'Lab Results - Sep 2024.pdf', type: 'Lab Result', date: '2024-09-15', size: '245 KB' },
    { id: '2', name: 'Imaging - X-Ray.pdf', type: 'Imaging', date: '2024-08-22', size: '1.2 MB' },
    { id: '3', name: 'Discharge Summary.pdf', type: 'Discharge Summary', date: '2024-07-10', size: '156 KB' },
  ];

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-lg shadow p-6">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold text-gray-900">Medical Documents</h1>
          <button
            className="bg-primary-600 text-white px-4 py-2 rounded-md hover:bg-primary-700"
            aria-label="Upload new document"
          >
            + Upload Document
          </button>
        </div>

        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200" role="table">
            <thead className="bg-gray-50">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Document Name
                </th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Type
                </th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Date
                </th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Size
                </th>
                <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {documents.map((doc) => (
                <tr key={doc.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <span className="text-2xl mr-3" aria-hidden="true">📄</span>
                      <span className="text-sm font-medium text-gray-900">{doc.name}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{doc.type}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {new Date(doc.date).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{doc.size}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                    <button
                      className="text-primary-600 hover:text-primary-900 mr-4"
                      aria-label={`View ${doc.name}`}
                    >
                      View
                    </button>
                    <button
                      className="text-primary-600 hover:text-primary-900"
                      aria-label={`Download ${doc.name}`}
                    >
                      Download
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Upload Instructions */}
      <div className="bg-blue-50 border border-blue-200 rounded-lg p-6">
        <h2 className="text-lg font-semibold text-blue-900 mb-2">Upload Guidelines</h2>
        <ul className="list-disc list-inside text-blue-800 text-sm space-y-1">
          <li>Supported formats: PDF, JPEG, PNG</li>
          <li>Maximum file size: 10 MB</li>
          <li>Documents are automatically OCR processed and mapped to FHIR resources</li>
          <li>All documents are encrypted and HIPAA compliant</li>
        </ul>
      </div>
    </div>
  );
}

